/**
 * "Ask the margin" lesson tutor — a response-streaming Lambda behind a Function
 * URL. It grounds a Claude answer (Amazon Bedrock, ConverseStream) in the single
 * lesson the learner is reading, refuses anything outside it, and never invents
 * Braket/PennyLane APIs.
 *
 * The prompt/grounding logic is imported from ./tutor-core.mjs (the single
 * source of truth, shared with web/src/lib/tutor.ts and the corpus builder).
 * corpus.json is generated by scripts/build_tutor_corpus.mjs.
 *
 * The per-request logic lives in `createHandlerCore` with its dependencies
 * (Bedrock client, corpus, model id) injected, so it can be unit-tested
 * (lambda/tutor/index.test.mjs) without the Lambda runtime, a real Bedrock call,
 * or a packaged corpus. The production `handler` wires the real dependencies
 * through the `awslambda` streaming wrapper.
 *
 * `awslambda` is a global provided by the Lambda Node runtime when response
 * streaming is enabled (InvokeMode: RESPONSE_STREAM on the Function URL).
 */
import { readFileSync } from "node:fs";
import { BedrockRuntimeClient, ConverseStreamCommand } from "@aws-sdk/client-bedrock-runtime";
import { buildSystemPrompt, OUT_OF_SCOPE_MESSAGE, TUTOR_ERROR_SENTINEL } from "./tutor-core.mjs";

// Re-exported so the handler test can assert the exact streamed strings.
export { OUT_OF_SCOPE_MESSAGE, TUTOR_ERROR_SENTINEL };

// corpus.json is generated by scripts/build_tutor_corpus.mjs and packaged at
// deploy time. Guard the read so importing this module in a test (where the
// gitignored corpus.json may be absent) never throws; production always ships it.
let CORPUS;
try {
  CORPUS = JSON.parse(readFileSync(new URL("./corpus.json", import.meta.url), "utf8"));
} catch (err) {
  // Structured warn (mirrors the error-path log below) so a deploy that forgot to
  // run build_tutor_corpus is visible in CloudWatch — otherwise an empty corpus
  // silently answers OUT_OF_SCOPE to every learner. (Absent in tests, which inject
  // their own fixture corpus; production always packages corpus.json.)
  console.warn(JSON.stringify({ tutorCorpusMissing: true, message: err?.message }));
  CORPUS = {};
}

const client = new BedrockRuntimeClient({});

// A legit request is tiny ({slug, question<=2000 chars}); reject anything larger
// before decoding/parsing so a public, unauthenticated URL can't be made to burn
// CPU/memory JSON-parsing a multi-MB body per invocation.
const MAX_BODY_BYTES = 16 * 1024;

function parseBody(event) {
  if (!event?.body) return {};
  if (event.body.length > MAX_BODY_BYTES) return {};
  const raw = event.isBase64Encoded ? Buffer.from(event.body, "base64").toString("utf8") : event.body;
  try {
    return JSON.parse(raw);
  } catch {
    return {};
  }
}

/**
 * The per-request tutor logic with dependencies injected. `client` is anything
 * with `.send(command)` returning `{ stream }` (an async-iterable of Converse
 * deltas); `corpus` maps slug -> { title, headings, text }; `modelId` is the
 * Bedrock model/inference-profile id. `stream` is any `{ write(s), end() }` sink
 * — the Lambda HttpResponseStream in prod, a fake in tests. Resolves when the
 * response has been fully written. On any failure it writes the in-band
 * TUTOR_ERROR_SENTINEL (the response is already committed as 200).
 */
export function createHandlerCore({ client, corpus, modelId }) {
  return async (event, stream) => {
    try {
      const body = parseBody(event);
      const slug = String(body.slug || "").slice(0, 64);
      const question = String(body.question || "").trim().slice(0, 2000);
      // Own-property lookup: a plain object inherits keys like "__proto__",
      // "constructor", and "toString", which would otherwise resolve to a truthy
      // (but text-less) value and slip past the grounding guard into a paid,
      // effectively ungrounded model call.
      const section = Object.prototype.hasOwnProperty.call(corpus, slug) ? corpus[slug] : undefined;

      if (!section || !question) {
        stream.write(OUT_OF_SCOPE_MESSAGE);
        stream.end();
        return;
      }

      const command = new ConverseStreamCommand({
        modelId,
        system: [{ text: buildSystemPrompt(section) }],
        messages: [{ role: "user", content: [{ text: question }] }],
        inferenceConfig: { maxTokens: 800, temperature: 0.2 },
      });

      const response = await client.send(command);
      for await (const item of response.stream) {
        const text = item.contentBlockDelta?.delta?.text;
        if (text) stream.write(text);
      }
      stream.end();
    } catch (err) {
      // Structured log so a CloudWatch metric filter can alarm on tutor failures —
      // the streamed response is already committed as 200, so neither the HTTP
      // status nor the Lambda Errors metric ever signals this on its own.
      console.error(JSON.stringify({ tutorError: true, name: err?.name, message: err?.message }));
      // In-band sentinel so the client enters its error state instead of rendering
      // the apology as part of the answer.
      stream.write(`${TUTOR_ERROR_SENTINEL}The tutor hit an error. Please try again.`);
      stream.end();
    }
  };
}

// `streamifyResponse` only exists on the `awslambda` global in the response-
// streaming Lambda runtime. NB: importing @aws-sdk/client-bedrock-runtime above
// itself defines a global `awslambda` as an empty object, so a mere existence
// check is insufficient — we capability-check for streamifyResponse. Outside the
// Lambda runtime (e.g. `node --test`) it is absent, so the module loads cleanly
// (handler === undefined) and the test can import createHandlerCore. In
// production the real runtime provides it and the streaming handler is created.
export const handler =
  typeof awslambda !== "undefined" && typeof awslambda.streamifyResponse === "function"
    ? awslambda.streamifyResponse((event, responseStream) => {
        const stream = awslambda.HttpResponseStream.from(responseStream, {
          statusCode: 200,
          headers: { "Content-Type": "text/plain; charset=utf-8" },
        });
        // Construct the core per-invocation so process.env.TUTOR_MODEL_ID is read
        // each call (unchanged from the previous inline handler).
        return createHandlerCore({ client, corpus: CORPUS, modelId: process.env.TUTOR_MODEL_ID })(event, stream);
      })
    : undefined;
